"use strict";(self.webpackChunkspanish_app=self.webpackChunkspanish_app||[]).push([[6249],{6249:e=>{e.exports=JSON.parse('{"36":{"words":[{"spanish":"el cambio clim\xe1tico","english":"climate change"},{"spanish":"la huella de carbono","english":"carbon footprint"},{"spanish":"reducir emisiones","english":"to reduce emissions"},{"spanish":"compensar emisiones","english":"to offset emissions"},{"spanish":"las energ\xedas renovables","english":"renewable energy"},{"spanish":"la energ\xeda solar distribuida","english":"distributed solar power"},{"spanish":"la energ\xeda e\xf3lica marina","english":"offshore wind power"},{"spanish":"el almacenamiento energ\xe9tico","english":"energy storage"},{"spanish":"la red el\xe9ctrica","english":"the power grid"},{"spanish":"la transici\xf3n energ\xe9tica","english":"the energy transition"},{"spanish":"los combustibles f\xf3siles","english":"fossil fuels"},{"spanish":"el impuesto al carbono","english":"carbon tax"},{"spanish":"el subsidio verde","english":"green subsidy"},{"spanish":"la deforestaci\xf3n","english":"deforestation"},{"spanish":"la reforestaci\xf3n","english":"reforestation"},{"spanish":"la biodiversidad","english":"biodiversity"},{"spanish":"el corredor ecol\xf3gico","english":"wildlife corridor"},{"spanish":"el h\xe1bitat protegido","english":"protected habitat"},{"spanish":"la sequ\xeda prolongada","english":"prolonged drought"},{"spanish":"la ola de calor","english":"heat wave"},{"spanish":"la resiliencia clim\xe1tica","english":"climate resilience"},{"spanish":"la adaptaci\xf3n clim\xe1tica","english":"climate adaptation"},{"spanish":"la mitigaci\xf3n","english":"mitigation"},{"spanish":"la econom\xeda circular","english":"circular economy"},{"spanish":"el reciclaje selectivo","english":"sorted recycling"},{"spanish":"el compostaje comunitario","english":"community composting"},{"spanish":"el vertedero saturado","english":"overfilled landfill"},{"spanish":"la contaminaci\xf3n atmosf\xe9rica","english":"air pollution"},{"spanish":"la huella h\xeddrica","english":"water footprint"},{"spanish":"la cadena de suministro","english":"supply chain"},{"spanish":"el consumo responsable","english":"responsible consumption"},{"spanish":"la compra a granel","english":"bulk buying"},{"spanish":"las pol\xedticas medioambientales","english":"environmental policies"},{"spanish":"el desarrollo sostenible","english":"sustainable development"},{"spanish":"la justicia ambiental","english":"environmental justice"},{"spanish":"la evaluaci\xf3n de impacto ambiental","english":"environmental impact assessment"},{"spanish":"el acuerdo vinculante","english":"binding agreement"},{"spanish":"el cumplimiento normativo","english":"regulatory compliance"},{"spanish":"la movilidad sostenible","english":"sustainable mobility"},{"spanish":"el transporte p\xfablico el\xe9ctrico","english":"electric public transport"},{"spanish":"restaurar ecosistemas","english":"to restore ecosystems"},{"spanish":"la p\xe9rdida de especies","english":"loss of species"},{"spanish":"la responsabilidad colectiva","english":"collective responsibility"},{"spanish":"los incentivos fiscales verdes","english":"green tax incentives"},{"spanish":"prohibir pl\xe1sticos de un solo uso","english":"to ban single-use plastics"}],"conversations":[{"id":1,"topic":"Zona de bajas emisiones y comercio local","dialog":[{"speaker":"Marta","spanish":"El ayuntamiento quiere ampliar la zona de bajas emisiones porque la calidad del aire ha empeorado y ya no basta con campa\xf1as voluntarias.","english":"The city council wants to expand the low-emission zone because air quality has worsened and voluntary campaigns are no longer enough."},{"speaker":"Javier","spanish":"Entiendo la urgencia, pero varios comerciantes temen que, si se restringiera el acceso sin una transici\xf3n clara, perder\xedan clientela antes de poder adaptarse.","english":"I understand the urgency, but several business owners fear that if access were restricted without a clear transition, they would lose customers before being able to adapt."},{"speaker":"Marta","spanish":"Por eso se propone que se refuercen los autobuses el\xe9ctricos y que las entregas se concentren a primera hora, de modo que el cambio no recaiga solo en los negocios.","english":"That is why the proposal includes strengthening electric bus service and concentrating deliveries early in the day, so the burden does not fall only on businesses."},{"speaker":"Javier","spanish":"Aun as\xed, me preocupa que se anuncie la medida como si todos partieran de la misma situaci\xf3n, cuando muchos vecinos mayores dependen del coche para moverse.","english":"Even so, I worry that the measure is being announced as if everyone were starting from the same place, when many older residents depend on the car to get around."},{"speaker":"Marta","spanish":"Los t\xe9cnicos dicen que, a menos que se reduzcan pronto las emisiones, seguir\xe1n aumentando los casos de asma y el coste sanitario acabar\xe1 pag\xe1ndolo todo el barrio.","english":"Technical experts say that unless emissions are reduced soon, asthma cases will keep rising and the whole neighborhood will end up paying the health costs."},{"speaker":"Javier","spanish":"Si el plan incluyera revisiones mensuales y ayudas para modernizar la log\xedstica, creo que ser\xeda m\xe1s f\xe1cil pedirle a la comunidad que asuma su parte.","english":"If the plan included monthly reviews and support to modernize logistics, I think it would be easier to ask the community to do its part."}],"questions":[{"question":"\xbfPor qu\xe9 Javier no rechaza por completo la propuesta municipal?","options":["Porque acepta la meta ambiental, pero quiere que se mitiguen los efectos sobre el comercio y la movilidad.","Porque cree que la contaminaci\xf3n no tiene relaci\xf3n con el tr\xe1fico urbano.","Porque ya ha decidido cerrar su negocio y mudarse del barrio.","Porque piensa que los vecinos mayores deber\xedan dejar de conducir inmediatamente."],"answer":"Porque acepta la meta ambiental, pero quiere que se mitiguen los efectos sobre el comercio y la movilidad.","answerIndex":0},{"question":"\xbfQu\xe9 condici\xf3n menciona Marta para que el cambio no recaiga solo en los negocios?","options":["Que se construya un aparcamiento subterr\xe1neo privado.","Que se refuercen el transporte p\xfablico y las entregas en horarios regulados.","Que se cancelen todas las restricciones durante el invierno.","Que se sustituya la medida por campa\xf1as publicitarias."],"answer":"Que se refuercen el transporte p\xfablico y las entregas en horarios regulados.","answerIndex":1},{"question":"\xbfQu\xe9 desenlace parece m\xe1s probable al final de la conversaci\xf3n?","options":["Que la propuesta se abandone por completo sin debate adicional.","Que se apruebe una versi\xf3n gradual con seguimiento y apoyo econ\xf3mico.","Que solo los comercios voten la medida en una consulta privada.","Que el barrio renuncie a cualquier pol\xedtica clim\xe1tica futura."],"answer":"Que se apruebe una versi\xf3n gradual con seguimiento y apoyo econ\xf3mico.","answerIndex":1}]},{"id":2,"topic":"Proveedores, costes y sostenibilidad empresarial","dialog":[{"speaker":"Elena","spanish":"He revisado la huella de carbono de nuestros proveedores y el m\xe1s barato tambi\xe9n es el que m\xe1s depende del carb\xf3n y de rutas mar\xedtimas ineficientes.","english":"I reviewed the carbon footprint of our suppliers, and the cheapest one is also the one that relies most heavily on coal and inefficient shipping routes."},{"speaker":"Diego","spanish":"No dudo del informe, pero si cambi\xe1ramos de proveedor este trimestre, el presupuesto podr\xeda desajustarse justo cuando el mercado sigue inestable.","english":"I do not doubt the report, but if we switched suppliers this quarter, the budget could be thrown off just as the market remains unstable."},{"speaker":"Elena","spanish":"La cuesti\xf3n es que llevamos a\xf1os anunciando objetivos clim\xe1ticos; ser\xeda incoherente que sigui\xe9ramos comprando igual solo porque la factura inmediata resulte menor.","english":"The issue is that we have spent years announcing climate goals; it would be inconsistent to keep buying the same way just because the immediate bill is lower."},{"speaker":"Diego","spanish":"\xbfY si negoci\xe1ramos un contrato escalonado para que el nuevo proveedor garantice trazabilidad y nosotros no absorbamos todo el coste de golpe?","english":"What if we negotiated a phased contract so the new supplier guarantees traceability and we do not absorb the whole cost all at once?"},{"speaker":"Elena","spanish":"Eso ayudar\xeda, siempre que se audite de verdad la cadena de suministro y que no se nos venda sostenibilidad de escaparate.","english":"That would help, as long as the supply chain is genuinely audited and we are not being sold cosmetic sustainability."},{"speaker":"Diego","spanish":"Entonces apoyar\xeda el cambio, porque podr\xedamos demostrar que la transici\xf3n se ha dise\xf1ado con criterios financieros y medioambientales a la vez.","english":"In that case I would support the change, because we could show that the transition was designed with both financial and environmental criteria in mind."}],"questions":[{"question":"\xbfCu\xe1l es el conflicto principal que se discute en la reuni\xf3n?","options":["La empresa quiere abandonar todos sus objetivos ambientales de inmediato.","La empresa debe elegir entre coherencia clim\xe1tica y presi\xf3n presupuestaria a corto plazo.","Los empleados no saben qu\xe9 proveedor vende productos m\xe1s duraderos.","Los directivos quieren trasladar la f\xe1brica a otro pa\xeds sin avisar."],"answer":"La empresa debe elegir entre coherencia clim\xe1tica y presi\xf3n presupuestaria a corto plazo.","answerIndex":1},{"question":"\xbfPara qu\xe9 insiste Elena en que se audite la cadena de suministro?","options":["Para asegurarse de que las promesas ecol\xf3gicas puedan comprobarse y no sean puro marketing.","Para despedir al proveedor actual antes de hablar con el nuevo.","Para evitar que el departamento financiero revise el contrato.","Para retrasar la decisi\xf3n hasta el pr\xf3ximo a\xf1o fiscal."],"answer":"Para asegurarse de que las promesas ecol\xf3gicas puedan comprobarse y no sean puro marketing.","answerIndex":0},{"question":"\xbfQu\xe9 tendr\xeda que ocurrir para que Diego apoye el cambio?","options":["Que la empresa deje de medir sus emisiones durante seis meses.","Que el proveedor antiguo reduzca los precios de forma dr\xe1stica.","Que se acuerde una transici\xf3n escalonada con garant\xedas verificables.","Que el informe se mantenga confidencial y no llegue a la direcci\xf3n."],"answer":"Que se acuerde una transici\xf3n escalonada con garant\xedas verificables.","answerIndex":2}]},{"id":3,"topic":"Reforestaci\xf3n tras el incendio","dialog":[{"speaker":"Sof\xeda","spanish":"Despu\xe9s del incendio, algunos proponen plantar pinos de crecimiento r\xe1pido para que el monte vuelva a verse verde cuanto antes.","english":"After the fire, some people are proposing fast-growing pines so the hillside looks green again as soon as possible."},{"speaker":"Carlos","spanish":"El problema es que, si solo pens\xe1ramos en la rapidez, repetir\xedamos el mismo modelo vulnerable que ya hab\xeda facilitado que el fuego se extendiera.","english":"The problem is that if we thought only about speed, we would repeat the same vulnerable model that had already helped the fire spread."},{"speaker":"Sof\xeda","spanish":"La bi\xf3loga del proyecto insiste en que se combinen especies aut\xf3ctonas y que se recupere el suelo antes de abrir de nuevo la pista tur\xedstica.","english":"The project biologist insists that native species be combined and that the soil recover before the tourist trail reopens."},{"speaker":"Carlos","spanish":"Tiene sentido, aunque habr\xe1 vecinos que se impacienten si no ven resultados visibles durante los primeros a\xf1os.","english":"That makes sense, although there will be neighbors who grow impatient if they do not see visible results during the first years."},{"speaker":"Sof\xeda","spanish":"Precisamente por eso se est\xe1 explicando que restaurar un ecosistema no equivale a pintar de verde una ladera, sino a devolverle diversidad y resistencia.","english":"That is exactly why people are being told that restoring an ecosystem is not the same as painting a hillside green, but rather giving it back diversity and resilience."},{"speaker":"Carlos","spanish":"Si el mensaje cala, quiz\xe1 se entienda que la recuperaci\xf3n lenta tambi\xe9n puede ser la m\xe1s responsable.","english":"If the message sinks in, people may understand that the slower recovery can also be the most responsible one."}],"questions":[{"question":"\xbfPor qu\xe9 se critica la idea de plantar solo pinos de crecimiento r\xe1pido?","options":["Porque los pinos no pueden crecer en zonas de monta\xf1a.","Porque ser\xeda una soluci\xf3n vistosa, pero volver\xeda a crear un bosque fr\xe1gil.","Porque la ley proh\xedbe cualquier reforestaci\xf3n despu\xe9s de un incendio.","Porque los turistas prefieren ver el suelo sin vegetaci\xf3n."],"answer":"Porque ser\xeda una soluci\xf3n vistosa, pero volver\xeda a crear un bosque fr\xe1gil.","answerIndex":1},{"question":"\xbfQu\xe9 debe ocurrir antes de reabrir la pista tur\xedstica?","options":["Que se construya un aparcamiento junto al bosque.","Que se recupere el suelo y se planifique con especies aut\xf3ctonas.","Que se talen todos los \xe1rboles quemados en una semana.","Que los vecinos voten entre hoteles y c\xe1mpines."],"answer":"Que se recupere el suelo y se planifique con especies aut\xf3ctonas.","answerIndex":1},{"question":"\xbfQu\xe9 mensaje intenta transmitir el proyecto a la comunidad?","options":["Que lo importante es ocultar cuanto antes las huellas del incendio.","Que la restauraci\xf3n consiste sobre todo en atraer m\xe1s visitantes al valle.","Que un ecosistema sano requiere diversidad y no solo una apariencia verde inmediata.","Que la recuperaci\xf3n del bosque depende exclusivamente de la lluvia."],"answer":"Que un ecosistema sano requiere diversidad y no solo una apariencia verde inmediata.","answerIndex":2}]},{"id":4,"topic":"Vuelos cortos y transporte ferroviario","dialog":[{"speaker":"Laura","spanish":"En el seminario se plante\xf3 que, cuando exista una alternativa ferroviaria razonable, se limiten los vuelos nacionales m\xe1s cortos para reducir emisiones.","english":"In the seminar, the idea came up that once a reasonable rail alternative exists, the shortest domestic flights should be limited to reduce emissions."},{"speaker":"Andr\xe9s","spanish":"La idea no me parece absurda, pero dudo que sea justa si primero no se invierte en trenes fiables y asequibles para quienes viajan por trabajo.","english":"The idea does not seem absurd to me, but I doubt it is fair if reliable and affordable trains are not funded first for people who travel for work."},{"speaker":"Laura","spanish":"Claro, por eso varios profesores defendieron que la restricci\xf3n solo deber\xeda aplicarse una vez que el servicio haya mejorado y que las regiones perif\xe9ricas no queden aisladas.","english":"Of course, which is why several professors argued that the restriction should apply only once service has improved and peripheral regions are not left isolated."},{"speaker":"Andr\xe9s","spanish":"Adem\xe1s, habr\xeda que calcular el efecto real, porque a veces se anuncian medidas simb\xf3licas que sirven para tranquilizar conciencias m\xe1s que para transformar h\xe1bitos.","english":"Besides, the real effect would have to be measured, because sometimes symbolic measures are announced that soothe consciences more than they change habits."},{"speaker":"Laura","spanish":"Tambi\xe9n se habl\xf3 de eso: nadie dijo que bastara con prohibir, sino que la medida tendr\xeda que formar parte de una pol\xedtica m\xe1s amplia de movilidad sostenible.","english":"That was discussed too: nobody said banning alone would be enough, but rather that the measure would have to be part of a broader sustainable mobility policy."},{"speaker":"Andr\xe9s","spanish":"Si se abordara as\xed, dejar\xeda de verse como castigo individual y podr\xeda entenderse como una responsabilidad compartida.","english":"If it were approached that way, it would stop being seen as an individual punishment and could be understood as a shared responsibility."}],"questions":[{"question":"\xbfQu\xe9 requisito considera Andr\xe9s indispensable antes de limitar vuelos cortos?","options":["Que se proh\xedba viajar por trabajo durante el invierno.","Que se construyan aeropuertos m\xe1s peque\xf1os en las regiones perif\xe9ricas.","Que existan trenes fiables y asequibles como alternativa real.","Que los estudiantes gestionen la pol\xedtica de transporte directamente."],"answer":"Que existan trenes fiables y asequibles como alternativa real.","answerIndex":2},{"question":"\xbfQu\xe9 cr\xedtica hace Andr\xe9s a algunas medidas clim\xe1ticas?","options":["Que a veces son simb\xf3licas y cambian poco en la pr\xe1ctica.","Que siempre se dise\xf1an pensando \xfanicamente en turistas.","Que suelen beneficiar demasiado al transporte ferroviario privado.","Que se aprueban sin apoyo de ning\xfan experto universitario."],"answer":"Que a veces son simb\xf3licas y cambian poco en la pr\xe1ctica.","answerIndex":0},{"question":"\xbfBajo qu\xe9 enfoque final estar\xeda m\xe1s dispuesto a aceptar la medida?","options":["Si se presentara como castigo ejemplar para los viajeros frecuentes.","Si formara parte de una estrategia amplia y compartida de movilidad sostenible.","Si se aplicara solo a quienes viven en grandes capitales.","Si sustituyera todas las dem\xe1s pol\xedticas medioambientales."],"answer":"Si formara parte de una estrategia amplia y compartida de movilidad sostenible.","answerIndex":1}]}],"stories":[{"id":1,"title":"El barrio que cambi\xf3 sus h\xe1bitos","sentences":[{"spanish":"Cuando se anunci\xf3 que el barrio hab\xeda superado varios l\xedmites de contaminaci\xf3n, muchos vecinos pensaron que la responsabilidad reca\xeda \xfanicamente en las f\xe1bricas cercanas.","english":"When it was announced that the neighborhood had exceeded several pollution limits, many residents thought the responsibility fell only on the nearby factories."},{"spanish":"Sin embargo, un informe que se hab\xeda presentado semanas antes mostr\xf3 que tambi\xe9n influ\xedan el tr\xe1fico diario, el desperdicio energ\xe9tico de los edificios y el consumo desechable.","english":"However, a report that had been presented weeks earlier showed that daily traffic, wasteful building energy use, and disposable consumption also played a role."},{"spanish":"A partir de entonces, se organizaron talleres para que se redujera el uso del coche, se separaran mejor los residuos y se aprovechara el compost comunitario.","english":"From then on, workshops were organized so that car use would be reduced, waste would be sorted better, and community compost would be put to use."},{"spanish":"Aunque al principio hubo dudas sobre si esas medidas ser\xedan suficientes, varias comunidades instalaron paneles solares y revisaron el aislamiento de sus bloques.","english":"Although there were doubts at first about whether those measures would be enough, several housing communities installed solar panels and improved their buildings\' insulation."},{"spanish":"Lo m\xe1s importante fue que nadie pretendi\xf3 quedar exento: incluso los comercios que tem\xedan perder ventas acabaron participando en campa\xf1as de entrega sostenible.","english":"Most importantly, nobody tried to exempt themselves: even the shops that feared losing sales ended up taking part in sustainable delivery campaigns."},{"spanish":"Un a\xf1o despu\xe9s, no solo hab\xeda bajado la huella de carbono del barrio, sino que tambi\xe9n se hab\xeda fortalecido la idea de que la transici\xf3n deb\xeda repartirse con justicia.","english":"A year later, not only had the neighborhood\'s carbon footprint gone down, but the idea that the transition had to be shared fairly had also grown stronger."}]},{"id":2,"title":"La cooperativa del valle y el parque e\xf3lico","sentences":[{"spanish":"La cooperativa agr\xedcola recibi\xf3 una propuesta para ceder terrenos a un parque e\xf3lico que promet\xeda empleo e ingresos estables.","english":"The farming cooperative received a proposal to lease land to a wind farm that promised jobs and steady income."},{"spanish":"Algunos socios celebraron que por fin se apostara por energ\xedas renovables, mientras que otros exigieron que se evaluara el impacto sobre las aves migratorias y el paisaje.","english":"Some members welcomed the long-awaited commitment to renewable energy, while others demanded that the impact on migratory birds and the landscape be assessed."},{"spanish":"Como el contrato no estaba del todo claro, se pidi\xf3 que se hiciera una consulta p\xfablica antes de que se firmara nada.","english":"Since the contract was not fully clear, a public consultation was requested before anything was signed."},{"spanish":"Durante las reuniones, se repiti\xf3 que no bastaba con llamar verde a un proyecto para que este resultara sostenible.","english":"During the meetings, people kept repeating that simply calling a project green was not enough to make it sustainable."},{"spanish":"Tras meses de debate, se acept\xf3 una versi\xf3n m\xe1s reducida del parque, la cual inclu\xeda corredores ecol\xf3gicos y fondos para restauraci\xf3n ambiental.","english":"After months of debate, a scaled-down version of the wind farm was accepted, one that included wildlife corridors and funds for environmental restoration."},{"spanish":"La decisi\xf3n no dej\xf3 a todo el mundo satisfecho, pero s\xed mostr\xf3 que el desarrollo sostenible exige negociaci\xf3n, datos y l\xedmites.","english":"The decision did not leave everyone satisfied, but it did show that sustainable development requires negotiation, evidence, and limits."}]},{"id":3,"title":"Cuando el r\xedo volvi\xf3 a respirar","sentences":[{"spanish":"Durante a\xf1os, se hab\xeda desviado tanta agua para usos industriales que el r\xedo del municipio casi dej\xf3 de sostener vida.","english":"For years, so much water had been diverted for industrial use that the town\'s river almost stopped sustaining life."},{"spanish":"Cuando la sequ\xeda se volvi\xf3 m\xe1s severa, qued\xf3 claro que no se pod\xeda seguir gestionando el recurso como si fuera infinito.","english":"When the drought grew more severe, it became clear that the resource could no longer be managed as if it were endless."},{"spanish":"Entonces se aprob\xf3 un plan por el que se limitaron ciertas extracciones, se moderniz\xf3 el riego y se restauraron las riberas que hab\xedan sido degradadas.","english":"A plan was then approved through which certain withdrawals were limited, irrigation was modernized, and the riverbanks that had been degraded were restored."},{"spanish":"Varios sectores protestaron, ya que tem\xedan que la producci\xf3n disminuyera, pero los estudios indicaban que el coste de no actuar ser\xeda a\xfan mayor.","english":"Several sectors protested because they feared output would fall, but the studies indicated that the cost of failing to act would be even greater."},{"spanish":"A medida que regresaron los insectos, los peces y las aves, muchos habitantes entendieron que la biodiversidad no era un lujo, sino una condici\xf3n para la resiliencia.","english":"As insects, fish, and birds returned, many residents came to understand that biodiversity was not a luxury, but a condition for resilience."},{"spanish":"El r\xedo no se recuper\xf3 de la noche a la ma\xf1ana, pero volvi\xf3 a respirar en cuanto la comunidad acept\xf3 que cuidar el ecosistema era cuidar su propio futuro.","english":"The river did not recover overnight, but it began to breathe again once the community accepted that caring for the ecosystem meant caring for its own future."}]}],"speaking":{"title":"Hablar sobre sostenibilidad avanzada","description":"Practica respuestas complejas sobre clima, pol\xedticas p\xfablicas, consumo y responsabilidad colectiva.","questions_and_answers":[{"question":{"spanish":"\xbfQu\xe9 deber\xeda hacer una ciudad para que se reduzca la contaminaci\xf3n del aire?","english":"What should a city do so that air pollution decreases?"},"answer":{"spanish":"Deber\xeda ampliar el transporte p\xfablico y abaratar los abonos para que m\xe1s gente deje el coche en casa.","english":"It should expand public transportation and lower pass prices so that more people leave the car at home."}},{"question":{"spanish":"\xbfC\xf3mo explicar\xedas qu\xe9 es la huella de carbono de una empresa?","english":"How would you explain what a company\'s carbon footprint is?"},"answer":{"spanish":"Es la cantidad total de emisiones que genera una empresa directa e indirectamente a lo largo de su actividad.","english":"It is the total amount of emissions a company generates directly and indirectly throughout its operations."}},{"question":{"spanish":"Si el gobierno subvencionara paneles solares, \xbfqu\xe9 cambiar\xeda?","english":"If the government subsidized solar panels, what would change?"},"answer":{"spanish":"Muchas familias podr\xedan instalar energ\xeda limpia y depender\xedan menos de los combustibles f\xf3siles.","english":"Many families could install clean energy and would depend less on fossil fuels."}},{"question":{"spanish":"\xbfQu\xe9 recomiendas para que se recicle mejor en un edificio grande?","english":"What do you recommend so that recycling works better in a large building?"},"answer":{"spanish":"Recomiendo que se coloquen contenedores claros en cada planta y que se expliquen las normas con ejemplos sencillos.","english":"I recommend placing clear bins on every floor and explaining the rules with simple examples."}},{"question":{"spanish":"\xbfQu\xe9 conflicto puede surgir con un parque e\xf3lico nuevo?","english":"What conflict can arise with a new wind farm?"},"answer":{"spanish":"Puede surgir un conflicto porque produce energ\xeda limpia, pero tambi\xe9n puede afectar al paisaje o a las rutas de aves si no se planifica bien.","english":"A conflict may arise because it produces clean energy, but it can also affect the landscape or bird routes if it is not planned well."}},{"question":{"spanish":"Di una recomendaci\xf3n para que las empresas reduzcan sus emisiones.","english":"Give one recommendation so that companies reduce their emissions."},"answer":{"spanish":"Es importante que revisen su cadena de suministro y que no compren siempre la opci\xf3n m\xe1s contaminante solo porque sea barata.","english":"It is important that they review their supply chain and do not always buy the most polluting option just because it is cheap."}},{"question":{"spanish":"\xbfQu\xe9 medidas se han tomado ya en tu comunidad para ser m\xe1s sostenible?","english":"What measures has your community already taken to become more sustainable?"},"answer":{"spanish":"En mi comunidad se han instalado luces eficientes y se ha empezado a separar mejor los residuos org\xe1nicos.","english":"In my community, efficient lighting has been installed and organic waste has started to be sorted more carefully."}},{"question":{"spanish":"\xbfC\xf3mo reducir\xedas el consumo de agua durante una sequ\xeda prolongada?","english":"How would you reduce water consumption during a prolonged drought?"},"answer":{"spanish":"Limitar\xeda el riego innecesario, reparar\xeda fugas y promover\xeda aparatos que gasten menos agua.","english":"I would limit unnecessary irrigation, fix leaks, and promote appliances that use less water."}},{"question":{"spanish":"\xbfPor qu\xe9 es esencial proteger la biodiversidad?","english":"Why is it essential to protect biodiversity?"},"answer":{"spanish":"Porque los ecosistemas que conservan su diversidad suelen resistir mejor las plagas, los incendios y los cambios bruscos.","english":"Because ecosystems that retain their diversity usually withstand pests, fires, and sudden changes better."}},{"question":{"spanish":"Menciona una pol\xedtica ambiental que pueda parecer impopular, pero necesaria.","english":"Mention one environmental policy that may seem unpopular but necessary."},"answer":{"spanish":"Cobrar por contaminar puede parecer impopular, pero a veces es necesario para que se acelere la transici\xf3n energ\xe9tica.","english":"Charging for pollution may seem unpopular, but it is sometimes necessary to speed up the energy transition."}},{"question":{"spanish":"\xbfQu\xe9 ocurrir\xe1 si se siguen priorizando los combustibles f\xf3siles?","english":"What will happen if fossil fuels keep being prioritized?"},"answer":{"spanish":"Seguir\xe1n aumentando las emisiones y ser\xe1 m\xe1s dif\xedcil adaptarse a fen\xf3menos extremos que ya se han intensificado.","english":"Emissions will keep rising and it will be harder to adapt to extreme events that have already intensified."}},{"question":{"spanish":"\xbfC\xf3mo definir\xedas la econom\xeda circular con un ejemplo?","english":"How would you define the circular economy with an example?"},"answer":{"spanish":"La definir\xeda como un modelo en el que se reutilizan materiales; por ejemplo, reparar aparatos para que no terminen enseguida en el vertedero.","english":"I would define it as a model in which materials are reused; for example, repairing devices so they do not end up in landfill so quickly."}},{"question":{"spanish":"Explica por qu\xe9 no basta con plantar \xe1rboles sin un plan serio.","english":"Explain why planting trees without a serious plan is not enough."},"answer":{"spanish":"No basta porque, si no se eligen especies adecuadas y no se cuida el suelo, el proyecto puede fracasar aunque se vea bien al principio.","english":"It is not enough because if suitable species are not chosen and the soil is not cared for, the project can fail even if it looks good at first."}},{"question":{"spanish":"\xbfQu\xe9 responsabilidad tienen los consumidores en la sostenibilidad?","english":"What responsibility do consumers have in sustainability?"},"answer":{"spanish":"Tienen la responsabilidad de informarse y de apoyar productos cuya producci\xf3n sea menos da\xf1ina para el entorno.","english":"They have the responsibility to stay informed and support products whose production is less harmful to the environment."}},{"question":{"spanish":"Menciona algo que hayas dejado de comprar para consumir de forma m\xe1s responsable.","english":"Mention something you have stopped buying in order to consume more responsibly."},"answer":{"spanish":"He dejado de comprar botellas peque\xf1as de pl\xe1stico y ahora llevo una reutilizable casi siempre.","english":"I have stopped buying small plastic bottles and now I carry a reusable one almost all the time."}},{"question":{"spanish":"Describe un proyecto que deba aprobarse solo despu\xe9s de una evaluaci\xf3n ambiental.","english":"Describe a project that should be approved only after an environmental assessment."},"answer":{"spanish":"Una carretera nueva que atraviese un h\xe1bitat protegido deber\xeda aprobarse solo si se demuestra que el da\xf1o puede evitarse o compensarse.","english":"A new road crossing a protected habitat should be approved only if it is shown that the damage can be avoided or offset."}},{"question":{"spanish":"\xbfC\xf3mo deber\xedan restaurarse los bosques despu\xe9s de un incendio?","english":"How should forests be restored after a fire?"},"answer":{"spanish":"Deber\xedan restaurarse con especies aut\xf3ctonas y con medidas que permitan que el suelo se recupere de verdad.","english":"They should be restored with native species and with measures that allow the soil to recover properly."}},{"question":{"spanish":"Compara un coste inmediato con un beneficio a largo plazo en pol\xedtica clim\xe1tica.","english":"Compare an immediate cost with a long-term benefit in climate policy."},"answer":{"spanish":"Puede costar modernizar edificios ahora, pero a largo plazo se ahorra energ\xeda y se reducen emisiones durante d\xe9cadas.","english":"It may be costly to retrofit buildings now, but in the long term energy is saved and emissions are reduced for decades."}},{"question":{"spanish":"Usa una frase impersonal con se para hablar de reciclaje en tu ciudad.","english":"Use an impersonal se sentence to talk about recycling in your city."},"answer":{"spanish":"En mi ciudad se recicla m\xe1s desde que se colocaron puntos limpios en los mercados.","english":"In my city, more recycling is done since drop-off points were placed in the markets."}},{"question":{"spanish":"Resume la idea de responsabilidad colectiva frente al cambio clim\xe1tico.","english":"Summarize the idea of collective responsibility in the face of climate change."},"answer":{"spanish":"Significa que ni los gobiernos, ni las empresas, ni los ciudadanos pueden actuar como si el problema perteneciera siempre a otro.","english":"It means that neither governments, nor companies, nor citizens can act as if the problem always belonged to someone else."}}]}}}')}}]);